// generar_239_rutinas_chiqui_cuidados.js
// CHIQUI Entre Señales — Ilustración chiqui_cuidados en Rutinas
//
// Cambia el encabezado de "Rutinas de cuidado" en Análisis: usa la
// nueva ilustración chiqui_cuidados.png (Chiqui rodeado de sus cosas
// de cuidado) en vez de chiqui_analisis. Los otros dos usos de
// chiqui_analisis en la pantalla no se tocan.
//
// Escribe app/analisis/page.tsx + public/chiqui/chiqui_cuidados.png.
// No hay SQL.
//
// Uso: arrastrar este archivo a la raíz del proyecto y correr:
//   node generar_239_rutinas_chiqui_cuidados.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: "app/analisis/page.tsx",
    base64: "",
    png: false
  },
  {
    ruta: "public/chiqui/chiqui_cuidados.png",
    base64: "",
    png: true
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64')
    if (a.png) { fs2.writeFileSync(rutaCompleta, contenido) }
    else { fs2.writeFileSync(rutaCompleta, contenido.toString('utf8'), 'utf8') }
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('\nListo. 1 archivo de código + 1 imagen. git add / commit / push.')
} else {
  console.error('\nTerminó con ' + errores + ' error(es). NO hagas push.')
  process.exit(1)
}
